import collections
import collections.abc
import functools
import heapq
import random
import time
from . import keys


class _DefaultSize:
    __slots__ = ()

    def __getitem__(self, _):
        raise NotImplementedError()

    def __setitem__(self, _, value):
        raise NotImplementedError()

    def pop(self, _):
        raise NotImplementedError()


class Cache(collections.abc.MutableMapping):
    """Mutable mapping to serve as a simple cache or cache base class."""
    __marker = object()
    __size = _DefaultSize()

    def __init__(self, maxsize, getsizeof=None):
        self._maxsize = maxsize
        self.data = {}
        if getsizeof is not None:
            self._getsizeof = getsizeof
            self.__size = {}

    def __repr__(self):
        return '%s(%r, currsize=%r)' % (
            self.__class__.__name__, self._maxsize, self.currsize,
        )

    @property
    def maxsize(self):
        """The maximum size of the cache."""
        return self._maxsize

    @property
    def currsize(self):
        """The current size of the cache."""
        if isinstance(self.__size, dict):
            return sum(self.__size.values())
        return len(self)

    @staticmethod
    def getsizeof(value):
        """Return the size of a cache element's value."""
        return 1

    def __getitem__(self, key):
        try:
            return self.data[key]
        except KeyError:
            return self.__missing__(key)

    def __setitem__(self, key, value):
        size = self._getsizeof(value)
        if size > self._maxsize:
            raise ValueError('value too large')
        if key in self.data:
            del self[key]
        if isinstance(self.__size, dict):
            self.__size[key] = size
        self.data[key] = value
        while self.currsize > self._maxsize:
            self.popitem()

    def __delitem__(self, key):
        try:
            if isinstance(self.__size, dict):
                del self.__size[key]
        except AttributeError:
            pass  # _DefaultSize doesn't support __delitem__
        del self.data[key]

    def __contains__(self, key):
        return key in self.data

    def __missing__(self, key):
        raise KeyError(key)

    def __iter__(self):
        return iter(self.data)

    def __len__(self):
        return len(self.data)

    def get(self, key, default=None):
        try:
            return self[key]
        except KeyError:
            return default

    def pop(self, key, default=__marker):
        try:
            value = self.data[key]
            del self[key]
            return value
        except KeyError:
            if default is self.__marker:
                raise
            return default

    def setdefault(self, key, default=None):
        if key not in self:
            self[key] = default
        return self[key]


class FIFOCache(Cache):
    """First In First Out (FIFO) cache implementation."""

    def __init__(self, maxsize, getsizeof=None):
        Cache.__init__(self, maxsize, getsizeof)
        self.data = collections.OrderedDict()

    def __setitem__(self, key, value, cache_setitem=Cache.__setitem__):
        cache_setitem(self, key, value)

    def __delitem__(self, key, cache_delitem=Cache.__delitem__):
        cache_delitem(self, key)

    def popitem(self):
        """Remove and return the `(key, value)` pair first inserted."""
        try:
            return self.data.popitem(last=False)
        except KeyError:
            raise KeyError('%s is empty' % type(self).__name__) from None


class LFUCache(Cache):
    """Least Frequently Used (LFU) cache implementation."""

    class _Link:
        __slots__ = ('count', 'keys', 'next', 'prev')

        def __init__(self, count):
            self.count = count
            self.keys = set()
            self.next = None
            self.prev = None

        def unlink(self):
            self.prev.next = self.next
            self.next.prev = self.prev
            self.prev = None
            self.next = None

    def __init__(self, maxsize, getsizeof=None):
        Cache.__init__(self, maxsize, getsizeof)
        self.__counter = 0
        self.__root = self._Link(0)

    def __getitem__(self, key, cache_getitem=Cache.__getitem__):
        value = cache_getitem(self, key)
        self.__touch(key)
        return value

    def __setitem__(self, key, value, cache_setitem=Cache.__setitem__):
        cache_setitem(self, key, value)
        if key in self:  # Only touch if still in cache
            self.__touch(key)

    def __delitem__(self, key, cache_delitem=Cache.__delitem__):
        link = self.__links.get(key)
        if link is not None:
            link.keys.discard(key)
            if not link.keys:
                link.unlink()
            del self.__links[key]
        cache_delitem(self, key)

    def popitem(self):
        """Remove and return the `(key, value)` pair least frequently used."""
        try:
            link = self.__root.next
            key = next(iter(link.keys))
            link.keys.discard(key)
            if not link.keys:
                link.unlink()
            value = self.data[key]
            del self[key]
            return key, value
        except (StopIteration, AttributeError):
            raise KeyError('%s is empty' % type(self).__name__) from None

    def __touch(self, key):
        link = self.__links.get(key)
        if link is not None:
            link.keys.discard(key)
            if not link.keys:
                link.unlink()
            next_link = link.next
            if next_link is None or next_link.count != link.count + 1:
                new_link = self._Link(link.count + 1)
                self.__splice(new_link, link)
            else:
                new_link = next_link
            new_link.keys.add(key)
            self.__links[key] = new_link
        else:
            self.__links[key] = self.__root
            self.__root.keys.add(key)

    def __splice(self, new_link, prev):
        next_link = prev.next
        new_link.prev = prev
        new_link.next = next_link
        prev.next = new_link
        if next_link is not None:
            next_link.prev = new_link

    def __get_counter(self):
        self.__counter += 1
        return self.__counter

    @property
    def __links(self):
        try:
            return self._LFU__links
        except AttributeError:
            self._LFU__links = {}
            return self._LFU__links


class LRUCache(Cache):
    """Least Recently Used (LRU) cache implementation."""

    def __init__(self, maxsize, getsizeof=None):
        Cache.__init__(self, maxsize, getsizeof)
        self.data = collections.OrderedDict()

    def __getitem__(self, key, cache_getitem=Cache.__getitem__):
        value = cache_getitem(self, key)
        self.__touch(key)
        return value

    def __setitem__(self, key, value, cache_setitem=Cache.__setitem__):
        cache_setitem(self, key, value)
        if key in self:
            self.__touch(key)

    def __delitem__(self, key, cache_delitem=Cache.__delitem__):
        cache_delitem(self, key)

    def popitem(self):
        """Remove and return the `(key, value)` pair least recently used."""
        try:
            return self.data.popitem(last=False)
        except KeyError:
            raise KeyError('%s is empty' % type(self).__name__) from None

    def __touch(self, key):
        self.data.move_to_end(key)


class RRCache(Cache):
    """Random Replacement (RR) cache implementation."""

    def __init__(self, maxsize, choice=random.choice, getsizeof=None):
        Cache.__init__(self, maxsize, getsizeof)
        self._choice = choice

    @property
    def choice(self):
        """The `choice` function used by the cache."""
        return self._choice

    def popitem(self):
        """Remove and return a random `(key, value)` pair."""
        try:
            key = self._choice(list(self.data.keys()))
            value = self.data[key]
            del self[key]
            return key, value
        except (KeyError, IndexError):
            raise KeyError('%s is empty' % type(self).__name__) from None


class _TimedCache(Cache):
    """Base class for time aware cache implementations."""

    class _Timer:

        def __init__(self, timer):
            self._timer = timer

        def __call__(self):
            return self._timer()

        def __enter__(self):
            return self._timer()

        def __exit__(self, *exc):
            pass

        def __reduce__(self):
            return (self._timer.__class__, ())

        def __getattr__(self, name):
            return getattr(self._timer, name)

    def __init__(self, maxsize, timer=time.monotonic, getsizeof=None):
        Cache.__init__(self, maxsize, getsizeof)
        self._timer = self._Timer(timer)

    def __repr__(self, cache_repr=Cache.__repr__):
        return cache_repr(self)

    def __len__(self, cache_len=Cache.__len__):
        return cache_len(self)

    @property
    def currsize(self):
        return Cache.currsize.fget(self)

    @property
    def timer(self):
        """The timer function used by the cache."""
        return self._timer

    def clear(self):
        Cache.clear(self)
        self._Timer__timestamp = self._timer()

    def get(self, *args, **kwargs):
        return Cache.get(self, *args, **kwargs)

    def pop(self, *args, **kwargs):
        return Cache.pop(self, *args, **kwargs)

    def setdefault(self, *args, **kwargs):
        return Cache.setdefault(self, *args, **kwargs)


class TTLCache(_TimedCache):
    """LRU Cache implementation with per-item time-to-live (TTL) value."""

    class _Link:
        __slots__ = ('key', 'expires', 'next', 'prev')

        def __init__(self, key=None, expires=None):
            self.key = key
            self.expires = expires
            self.next = None
            self.prev = None

        def __reduce__(self):
            return (TTLCache._Link, (self.key, self.expires))

        def unlink(self):
            self.prev.next = self.next
            self.next.prev = self.prev
            self.prev = None
            self.next = None

    def __init__(self, maxsize, ttl, timer=time.monotonic, getsizeof=None):
        _TimedCache.__init__(self, maxsize, timer, getsizeof)
        self._ttl = ttl
        self._Timer__timestamp = self._timer()  # name-mangled

    def __contains__(self, key):
        try:
            self[key]
            return True
        except KeyError:
            return False

    def __getitem__(self, key, cache_getitem=Cache.__getitem__):
        value = cache_getitem(self, key)
        self.__touch(key)
        return value

    def __setitem__(self, key, value, cache_setitem=Cache.__setitem__):
        cache_setitem(self, key, value)
        if key in self:
            self.__touch(key)

    def __delitem__(self, key, cache_delitem=Cache.__delitem__):
        link = self.__links.get(key)
        if link is not None:
            link.unlink()
            del self.__links[key]
        cache_delitem(self, key)

    def __iter__(self):
        root = self.__head
        curr = root.next
        while curr is not root:
            key = curr.key
            if self.__has_expired(curr):
                curr = curr.next
                continue
            yield key
            curr = curr.next

    def __setstate__(self, state):
        self.__dict__.update(state)
        # Rebuild the link structure
        self._Timer__timestamp = self._timer()

    @property
    def ttl(self):
        """The time-to-live value of the cache's items."""
        return self._ttl

    def expire(self, time=None):
        """Remove expired items from the cache and return an iterable of the
        expired `(key, value)` pairs.

        """
        if time is None:
            time = self._timer()
        expired = []
        root = self.__head
        curr = root.next
        while curr is not root:
            if curr.expires <= time:
                expired.append((curr.key, self.data[curr.key]))
                self.__delitem(curr.key)
            curr = root.next
        return expired

    def popitem(self):
        """Remove and return the `(key, value)` pair least recently used that
        has not already expired.

        """
        self.expire()
        try:
            root = self.__head
            curr = root.next
            while curr is not root:
                if curr.expires < float('inf'):
                    break
                curr = curr.next
            if curr is root:
                curr = root.next  # all have inf, just take the LRU
            key = curr.key
            value = self.data[key]
            del self[key]
            return key, value
        except (KeyError, AttributeError):
            raise KeyError('%s is empty' % type(self).__name__) from None

    def __touch(self, key):
        link = self.__links.get(key)
        if link is not None:
            link.unlink()
        else:
            link = self._Link(key)
            self.__links[key] = link
        link.expires = self._timer() + self._ttl
        self.__append(link)

    @property
    def __head(self):
        try:
            return self._TTLCache__head
        except AttributeError:
            root = self._Link()
            root.next = root
            root.prev = root
            self._TTLCache__head = root
            return root

    @property
    def __links(self):
        try:
            return self._TTLCache__links
        except AttributeError:
            self._TTLCache__links = {}
            return self._TTLCache__links

    def __append(self, link):
        root = self.__head
        prev = root.prev
        link.prev = prev
        link.next = root
        prev.next = link
        root.prev = link

    def __getlink(self, key):
        return self.__links.get(key)

    def __has_expired(self, link):
        return link.expires <= self._timer()


class TLRUCache(_TimedCache):
    """Time aware Least Recently Used (TLRU) cache implementation."""

    @functools.total_ordering
    class _Item:
        __slots__ = ('key', 'expires', 'removed')

        def __init__(self, key=None, expires=None):
            self.key = key
            self.expires = expires
            self.removed = False

        def __lt__(self, other):
            return self.expires < other.expires

    def __init__(self, maxsize, ttu, timer=time.monotonic, getsizeof=None):
        _TimedCache.__init__(self, maxsize, timer, getsizeof)
        self._ttu = ttu
        self.__heap = []
        self.__lookup = {}

    def __contains__(self, key):
        try:
            self[key]
            return True
        except KeyError:
            return False

    def __getitem__(self, key, cache_getitem=Cache.__getitem__):
        value = cache_getitem(self, key)
        self.__touch(key)
        return value

    def __setitem__(self, key, value, cache_setitem=Cache.__setitem__):
        cache_setitem(self, key, value)
        if key in self:
            self.__touch(key)

    def __delitem__(self, key, cache_delitem=Cache.__delitem__):
        try:
            item = self.__lookup[key]
            item.removed = True
            del self.__lookup[key]
        except KeyError:
            pass
        cache_delitem(self, key)

    def __iter__(self):
        time = self._timer()
        for key, item in list(self.__lookup.items()):
            if item.removed:
                continue
            if item.expires <= time:
                continue
            yield key

    @property
    def ttu(self):
        """The local time-to-use function used by the cache."""
        return self._ttu

    def expire(self, time=None):
        """Remove expired items from the cache and return an iterable of the
        expired `(key, value)` pairs.

        """
        if time is None:
            time = self._timer()
        expired = []
        while self.__heap:
            item = self.__heap[0]
            if item.expires > time:
                break
            heapq.heappop(self.__heap)
            if item.removed:
                continue
            if item.key not in self.__lookup:
                continue
            expired.append((item.key, self.data[item.key]))
            del self[item.key]
        return expired

    def popitem(self):
        """Remove and return the `(key, value)` pair least recently used that
        has not already expired.

        """
        self.expire()
        try:
            # Evict the LRU item that hasn't expired (use the ordered keys)
            for key in list(self.data.keys()):
                item = self.__lookup.get(key)
                if item is not None and not item.removed and item.expires > self._timer():
                    value = self.data[key]
                    del self[key]
                    return key, value
            # All items have expired or been removed
            raise KeyError('%s is empty' % type(self).__name__)
        except (StopIteration, KeyError):
            raise KeyError('%s is empty' % type(self).__name__) from None

    def __touch(self, key):
        item = self.__lookup.get(key)
        if item is not None:
            item.removed = True
        expires = self._ttu(key, self.data[key], self._timer())
        new_item = self._Item(key, expires)
        self.__lookup[key] = new_item
        heapq.heappush(self.__heap, new_item)

    def __getitem(self, key):
        return self.__lookup[key]


_CacheInfo = collections.namedtuple(
