def cached(cache, key=keys.hashkey, lock=None, condition=None, info=False):
    """Decorator to wrap a function with a memoizing callable that saves
    results in a cache.

    """
    if not info:
        return _cached._wrapper(cache, key, lock, condition)
    else:
        return _cached._wrapper(cache, key, lock, condition, True)


def cachedmethod(cache, key=keys.methodkey, lock=None, condition=None):
    """Decorator to wrap a class or instance method with a memoizing
    callable that saves results in a cache.

    """
    return _cachedmethod._wrapper(cache, key, lock, condition)


